mapper.select:
SELECT o.id, o.source_type, o.opportunity_name, o.opportunity_type, o.opportunity_status, s.service_name, o.expected_amount, o.expected_close_date, o.description, o.created_time FROM szzw.t_yqyc_biz_opportunity o LEFT JOIN szzw.t_yqyc_biz_service s ON s.id = o.service_id WHERE o.group_id = #{groupId}
AND o.opportunity_status = #{status}
AND o.opportunity_type = #{type}
AND o.source_type = #{sourceType}
ORDER BY o.created_time DESC
